-- ── PdfDing ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PdfDing is a free, open-source, self-hosted PDF manager and viewer that lets users organize, annotate, and access PDF documents across devices via a Docker-deployed web app.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PdfDing Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PdfDing review covering this open-source, self-hosted PDF manager and viewer: features, Docker setup, pricing, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PdfDing is a free and open-source, self-hosted PDF manager, viewer, and lightweight editor designed to give individuals and organizations full control over their document storage instead of relying on a third-party cloud PDF service. Built with the Django web framework and distributed under an open-source license, PdfDing is developed primarily by a maintainer known as mrmn2 and hosted on both GitHub and Codeberg, where the project has attracted over 1,700 GitHub stars, reflecting notable traction within the self-hosting and privacy-focused open-source community. The project received funding support from the NGI0 Commons Fund, established by NLnet with backing from the European Commission, which supports privacy-respecting and open internet technologies. PdfDing is deployed using Docker, Docker Compose, or Helm for Kubernetes, and is designed to be minimal, fast, and easy to set up on a home server, NAS, or self-managed cloud instance. Core features include a browser-based PDF viewer that remembers your reading position across devices, multi-level organization through tagging, starring, and archiving, basic editing capabilities such as adding text, highlights, and drawings, digital signature support, and sharing via links or QR codes with optional access controls. It also supports single sign-on through OIDC and two-factor authentication for security-conscious deployments, along with dark mode and customizable themes. Because there is no company behind PdfDing and no paid tier, its pricing model is purely open source: the software itself is free, though users bear their own hosting costs such as a VPS, home server, or NAS. PdfDing's target users are privacy-conscious individuals, developers, and small teams who want a self-hosted alternative to cloud PDF readers and managers. Its closest competitors in the self-hosted document space include Paperless-ngx, which focuses more on document scanning and archiving, Stirling PDF, a self-hosted PDF editing toolkit, and general-purpose file managers like Nextcloud when used for PDF storage. PdfDing distinguishes itself by focusing specifically on reading and light editing convenience across devices rather than heavyweight document management or OCR-based archiving.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7407b9cd-1500-4f27-a02b-adda67302c80';

