-- ── PDFescape ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PDFescape is a free, browser-based PDF editor and form filler, now owned by Claranova's Avanquest division, offering both a free online tool and paid Premium/Ultimate tiers.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; Premium from $3/month, Ultimate from $6/month$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$Part of Claranova (Avanquest); standalone team size not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Montreal, Canada (part of Claranova / Avanquest Software)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PDFescape Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PDFescape review covering the free online PDF editor and form filler, Premium and Ultimate pricing, features, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PDFescape is a browser-based PDF editing and form-filling tool that has offered a genuinely free online tier since its early years, distinguishing it from many competitors that gate core editing behind a paywall. It was established in Montreal, Canada, by software developers Roger Politis and Bruno Vanryb under the company CTdeveloping, LLC, with the two having earlier co-founded BVRP Software and contributed to Avanquest Software. In March 2021, PDFescape was acquired by Avanquest, the software publishing division of the French group Claranova, bringing it under a larger, publicly traded parent company. PDFescape's free online tool lets users edit PDF text and images, fill and design PDF forms, and annotate documents directly in a browser without installing software, though the free tier caps file size at 10 MB, page count at 100, limits storage to 10 files, and retains file history for only seven days while adding no watermark to prints or saves. Paid tiers remove ad interruptions and raise limits: Premium, around 3 dollars per month, increases the file-size cap to 40 MB, stores up to 100 files, and extends history to 30 days, while Ultimate, around 6 dollars per month, adds an unlimited-history desktop application with advanced tools such as PDF creation from over 300 file types, merging, compression, encryption, redaction, and e-signatures. PDFescape's target users are individuals, students, and small businesses who need occasional PDF editing or form-filling without committing to a full subscription like Adobe Acrobat. Its main competitors include Adobe Acrobat, Smallpdf, PDF Expert, and other browser-based tools such as Sejda and DocHub, with PDFescape differentiating itself primarily through its long-standing genuinely free online editor rather than a time-limited trial. Because it runs in the browser, PDFescape works across Windows, Mac, and Linux without installation for its free tier, making it a common choice for users who need quick, occasional edits rather than a full-featured, ongoing PDF workflow.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e66e1448-1366-4bae-8a4e-3bcd643199a5';

