-- ── PeerTube ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PeerTube is a free, open-source, decentralized video hosting platform using ActivityPub federation and peer-to-peer streaming, developed since 2017 with support from the French non-profit Framasoft.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); some hosted instances offer paid storage options$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Lyon, France (Framasoft)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Spanish$q$, $q$Italian$q$, $q$Portuguese$q$, $q$Russian$q$, $q$Chinese$q$, $q$Japanese$q$, $q$Dutch$q$]::text[],
  seo_title = COALESCE($q$PeerTube Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PeerTube review covering this open-source, federated video hosting platform: features, self-hosting, pricing, pros, cons, and YouTube alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PeerTube is a free and open-source video hosting platform designed as a decentralized alternative to YouTube, Vimeo, and Dailymotion. It was started in 2017 by a French developer known by the handle Chocobozzz as a personal project, and development has since been supported by Framasoft, a French non-profit association headquartered in Lyon that promotes free software and digital commons education. Framasoft hired the original developer and later ran successful crowdfunding campaigns, including one that raised over 53,000 euros in 2018, more than double its goal, and another that reached a 60,000 euro target by October 2020, partly thanks to a 10,000 euro donation from the Debian project. PeerTube's first beta shipped in March 2018 and its first stable 1.0 release arrived in October 2018; by mid-2018 it already had over 100 independent instances collectively hosting more than 10,000 videos. Rather than relying on one centralized company running all the infrastructure, PeerTube lets anyone run their own instance, and instances can federate with one another using the W3C ActivityPub protocol, the same standard used by Mastodon, so that videos, comments, and subscriptions can be discovered and interacted with across independently operated servers as part of the wider Fediverse. To reduce bandwidth costs for instance operators, PeerTube also uses peer-to-peer streaming via WebRTC and HLS, letting viewers share video data with each other while watching. The software is licensed under the AGPLv3+ and is available in around 28 languages through community translation. PeerTube's target users are content creators, communities, universities, media organizations, and activist groups who want to avoid centralized platform moderation, algorithmic recommendation systems, and advertising, or who want to control their own video infrastructure and monetization. There is no central PeerTube company selling subscriptions; instead, the software itself is free, and pricing only applies if a user chooses to pay for storage or hosting on a third-party PeerTube instance rather than running their own server for free. Its main points of comparison are YouTube and Vimeo for centralized video hosting, and Owncast or PixelFed for other Fediverse-native media platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '43fecc1e-117b-4ec8-ae44-12dc137692b9';

