INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Multi-currency receiving accounts$q$, $q$Local receiving accounts in the US, UK, EU, Japan, and other markets let users get paid like a local without a foreign bank account.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Marketplace payouts integration$q$, $q$Deep integrations with Amazon, Airbnb, Upwork, Fiverr, and other marketplaces make Payoneer a default payout option for global sellers and freelancers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Currency conversion$q$, $q$Convert received funds into a local currency before withdrawing to a linked bank account.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Payoneer Checkout$q$, $q$An e-commerce payment acceptance product letting online sellers accept cards and local payment methods from global customers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Mass payouts for businesses$q$, $q$Enterprises can pay large numbers of contractors, sellers, or affiliates in different countries from a single dashboard.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Prepaid Mastercard$q$, $q$A physical and virtual Payoneer card lets users spend received funds directly or withdraw cash at ATMs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Working capital$q$, $q$Eligible e-commerce sellers can access short-term capital advances against future receivables.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Payouts API$q$, $q$Marketplaces and platforms can embed Payoneer payment infrastructure directly into their own products.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Free to open an account, with no monthly subscription fee for the core service$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Wide network covering 190+ countries with local receiving accounts in major currencies$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Deep integration with major freelance and e-commerce marketplaces$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Publicly traded company with transparent financial reporting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Mass payout tools suited to enterprises paying many international recipients$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Currency conversion and withdrawal fees can add up for frequent users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Customer support response times are inconsistent according to user reviews$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Account holds and verification requirements can delay access to funds$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Less suited to casual peer-to-peer payments than consumer wallets like PayPal$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Fee structures vary by country and account type, making costs hard to predict upfront$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Is Payoneer free to use?$q$, $q$Opening a Payoneer account is free; the company charges fees for currency conversion, withdrawals, and some marketplace-specific transactions rather than a subscription fee.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$How is Payoneer different from PayPal?$q$, $q$Payoneer focuses on B2B cross-border receivables, marketplace payouts, and local receiving accounts, while PayPal is a broader consumer-and-business wallet built around peer-to-peer and checkout payments.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Is Payoneer publicly traded?$q$, $q$Yes, Payoneer Global Inc. trades on Nasdaq under the ticker PAYO after going public via a SPAC merger in 2021.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$What currencies does Payoneer support?$q$, $q$Payoneer supports receiving and holding balances in major currencies such as USD, EUR, GBP, and JPY, with local receiving accounts in several markets.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Which marketplaces integrate with Payoneer?$q$, $q$Amazon, Airbnb, Upwork, Fiverr, Walmart, and many other global marketplaces offer Payoneer as a payout option for sellers and freelancers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Does Payoneer offer a debit card?$q$, $q$Yes, Payoneer issues a prepaid Mastercard that lets customers spend or withdraw received funds.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Who founded Payoneer?$q$, $q$Payoneer was founded in 2005 by Yuval Tal.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Where is Payoneer headquartered?$q$, $q$Payoneer is headquartered in New York City, with offices in more than 20 countries.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Freelancer international payouts$q$, $q$Freelancers on platforms like Upwork and Fiverr use Payoneer to receive client payments in their preferred currency without opening a foreign bank account.$q$, $q$Freelancers and independent contractors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$E-commerce marketplace seller payments$q$, $q$Amazon and other marketplace sellers use Payoneer to collect proceeds from international sales and convert them to their local currency.$q$, $q$E-commerce sellers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Enterprise mass payouts$q$, $q$Businesses that need to pay hundreds or thousands of overseas affiliates, creators, or vendors use Payoneer's mass payout API to automate international disbursements.$q$, $q$Enterprises and platforms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Individual/Freelancer Account$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["No monthly fee to open or maintain an account","Local receiving accounts in multiple currencies","Prepaid Mastercard available","Fees apply for currency conversion and withdrawals"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Business Account$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["No monthly subscription fee","Mass payout tools for paying multiple recipients","Marketplace and API integrations","Fees apply per transaction and currency conversion"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$Payoneer Checkout$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["E-commerce payment acceptance","Support for cards and local payment methods","Custom pricing based on transaction volume"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Payoneer is a global payments company that lets freelancers, e-commerce sellers, and businesses receive, hold, and move money across borders without needing a foreign bank account. Founded in 2005 and headquartered in New York City, Payoneer has grown from a prepaid-card business into a publicly traded (Nasdaq: PAYO) payments infrastructure provider used by millions of customers worldwide.$q$, $q$The platform is best known for local receiving accounts that let sellers on marketplaces like Amazon, Upwork, and Fiverr collect payments as if they held a bank account in the buyer's country, then convert and withdraw the funds through Payoneer.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Payoneer's core product is its multi-currency account, which supports local receiving accounts in major markets and a prepaid Mastercard for spending or withdrawing funds. Businesses can also use Payoneer Checkout to accept payments from global customers on their own websites.$q$, $q$For larger organizations, Payoneer offers mass payout tools and an API that let platforms and marketplaces pay thousands of overseas contractors, sellers, or affiliates from a single dashboard, along with optional working-capital advances for eligible e-commerce sellers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f63dc78f-9d0d-4816-9ca0-858dd2947329', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Payoneer does not charge a monthly subscription fee for its core account; both individual and business accounts are free to open. Instead, Payoneer generates revenue through currency conversion spreads, withdrawal fees, and small percentage fees on certain marketplace or B2B payments.$q$, $q$Because fees vary by country, currency corridor, and payment source, actual costs depend heavily on how and where a user sends or receives money. Payoneer Checkout and enterprise mass-payout services are typically priced on a custom basis for higher-volume users.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$PayPal Checkout$q$, $q$A one-click checkout button that online stores embed to let customers pay with a PayPal balance, card, or bank account.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Peer-to-peer transfers$q$, $q$Send money instantly to friends and family using an email address or phone number.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Pay in 4$q$, $q$A buy-now-pay-later option that lets shoppers split eligible purchases into four installments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Invoicing$q$, $q$Create and send professional invoices for freelancers and small businesses to collect client payments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Braintree integration$q$, $q$A full-stack payment processing platform for larger merchants needing cards, wallets, and local payment methods.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Venmo integration$q$, $q$Social peer-to-peer payments popular among US consumers, owned and operated by PayPal.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Currency conversion$q$, $q$Accept and convert international payments for cross-border e-commerce.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$PayPal and Venmo cards$q$, $q$Debit and credit cards that let users spend their PayPal or Venmo balance directly.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Extremely wide merchant and consumer adoption worldwide$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Free to open a personal account with no monthly fee$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Buyer and seller protection programs on eligible purchases$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Broad product range spanning Checkout, Braintree, Venmo, invoicing, and Pay in 4$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Recognized, trusted brand that can improve online checkout conversion$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Transaction fees can be higher than some competitors for small businesses$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Account holds or freezes are a recurring user complaint$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Customer support can be slow to resolve disputes$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Currency conversion rates include a markup over market rates$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Is PayPal free?$q$, $q$Personal accounts are free to open; PayPal earns revenue from merchant transaction fees and certain transfer or conversion fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Who founded PayPal?$q$, $q$Confinity, PayPal's predecessor, was founded in 1998 by Peter Thiel, Max Levchin, and Luke Nosek; it merged with X.com in 2000 and adopted the PayPal name in 2001.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Is PayPal publicly traded?$q$, $q$Yes, PayPal Holdings trades on Nasdaq under the ticker PYPL and has been independent since its 2015 spinoff from eBay.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$What is the difference between PayPal and Payoneer?$q$, $q$PayPal is primarily a consumer wallet and merchant checkout brand, while Payoneer focuses on B2B cross-border payouts and marketplace seller receivables.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Does PayPal own Venmo?$q$, $q$Yes, Venmo is a PayPal-owned peer-to-peer payment app popular in the United States.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$What is Braintree?$q$, $q$Braintree is PayPal's payment processing subsidiary used by larger merchants and platforms to accept card and digital wallet payments.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Where is PayPal headquartered?$q$, $q$PayPal is headquartered in San Jose, California.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Does PayPal offer buy now pay later?$q$, $q$Yes, through its Pay in 4 installment product.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Online checkout for e-commerce$q$, $q$Merchants embed PayPal Checkout to let customers pay with a PayPal balance, card, or bank account.$q$, $q$E-commerce merchants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Peer-to-peer money transfers$q$, $q$Consumers send money to friends and family instantly using an email address or phone number.$q$, $q$Consumers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Freelance invoicing and payment collection$q$, $q$Freelancers send invoices and collect client payments through PayPal's invoicing tools.$q$, $q$Freelancers and small businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Personal Account$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Send and receive money","Pay in 4 installment option","Linked bank account, card, or PayPal balance","Buyer protection on eligible purchases"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Business Account$q$, $q$Free to open (per-transaction fees apply)$q$, $q$N/A$q$, NULL, $q$["Accept online and in-person payments","Invoicing tools","Seller protection program","Access to PayPal Checkout and APIs"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Braintree (Enterprise Payment Processing)$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Full-stack payment processing","Support for cards, wallets, and local payment methods","Developer APIs and SDKs","Volume-based custom pricing"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PayPal is a publicly traded online payments company that lets consumers pay online, send money to friends and family, and lets merchants accept payments on their websites and apps. It traces its roots to Confinity, founded in 1998, and has operated as an independent public company (Nasdaq: PYPL) since its 2015 spinoff from eBay.$q$, $q$Headquartered in San Jose, California, PayPal is one of the most widely recognized names in digital payments, with deep integration across online retailers worldwide and ownership of Venmo, a leading US peer-to-peer payment app.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Consumers use PayPal to shop online, send peer-to-peer transfers, and split purchases with the Pay in 4 buy-now-pay-later option. A linked PayPal or Venmo card also lets users spend their balance directly.$q$, $q$Merchants rely on PayPal Checkout and invoicing tools for smaller businesses, while larger platforms use Braintree, PayPal's payment processing subsidiary, to accept cards and digital wallets at scale.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Opening a personal PayPal account is free, and there is no monthly subscription fee for standard use. PayPal instead earns revenue through per-transaction fees charged to merchants, along with fees on certain transfers, currency conversion, and instant withdrawals.$q$, $q$Business and Braintree pricing scales with transaction volume and payment methods accepted, and larger merchants can negotiate custom rates directly with PayPal.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Lifetime one-time payment plans$q$, $q$Pay once for 500GB, 2TB, or 10TB of storage that lasts as long as the service operates, unlike typical subscription cloud storage.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Cross-platform sync$q$, $q$Desktop, mobile, and web apps keep files synced across Windows, Mac, Linux, iOS, and Android.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Built-in media player$q$, $q$Stream video and audio files directly from cloud storage without downloading.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$pCloud Encryption (Crypto)$q$, $q$An optional paid add-on that gives client-side, zero-knowledge encryption for a private folder.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$File sharing and links$q$, $q$Share files and folders via public links with optional passwords and expiration dates.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Data center choice$q$, $q$Store data in EU (Luxembourg) or US data centers depending on account settings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Family plan$q$, $q$Share a single storage allocation with up to 5 family members.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Automatic backup$q$, $q$Back up folders from computers and connected cloud accounts like Google Drive or Dropbox.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Unique one-time lifetime payment option avoids recurring subscription costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Choice of EU or US data center location$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Built-in media player for streaming stored video and audio$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Generous storage tiers up to 10TB$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Family plan lets multiple users share one allocation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Zero-knowledge encryption (Crypto) is sold as a separate paid add-on rather than included by default$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Large upfront cost for lifetime plans is a barrier for some users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Sync speed and interface have received mixed reviews compared to larger competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Fewer third-party app integrations than Google Drive or Dropbox$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$What is pCloud's lifetime plan?$q$, $q$A one-time payment that grants a fixed amount of storage for as long as pCloud remains in operation, instead of a recurring subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Is pCloud encrypted by default?$q$, $q$No, base storage is not zero-knowledge encrypted; client-side encryption is available through the separate pCloud Encryption (Crypto) add-on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Where is pCloud based?$q$, $q$pCloud is headquartered in Baar, Switzerland, and was founded in 2013.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Can I choose where my data is stored?$q$, $q$Yes, pCloud lets users choose between European Union and United States data centers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Does pCloud have a free plan?$q$, $q$Yes, pCloud offers 10 GB of free storage.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$What is the difference between pCloud and Dropbox?$q$, $q$pCloud offers one-time lifetime payment plans and a built-in media player, while Dropbox is subscription-only and focuses more on collaboration and integrations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Does pCloud support family sharing?$q$, $q$Yes, a Family plan lets up to 5 users share one storage pool.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Is pCloud's lifetime plan really a one-time payment?$q$, $q$Yes, it is a genuine one-time payment for the storage tier selected, with no recurring billing afterward.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Long-term personal file backup$q$, $q$Individuals who want predictable storage costs pay once for a lifetime plan instead of ongoing subscription fees.$q$, $q$Individuals and families$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Media streaming and photo storage$q$, $q$Photographers and media creators use pCloud's built-in player to store and stream large video and photo libraries.$q$, $q$Photographers and content creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Privacy-focused file storage$q$, $q$Privacy-conscious users add pCloud Encryption to keep a folder end-to-end encrypted and choose EU data center storage.$q$, $q$Privacy-conscious professionals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["10 GB storage","Cross-platform sync","File sharing links"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Premium (500GB)$q$, $q$$4.99/month or $199 one-time lifetime$q$, $q$Monthly, annual, or lifetime$q$, NULL, $q$["500 GB storage","500 GB download link traffic","Built-in media player","File versioning"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Premium Plus (2TB)$q$, $q$$9.99/month or $399 one-time lifetime$q$, $q$Monthly, annual, or lifetime$q$, NULL, $q$["2 TB storage","2 TB download link traffic","Priority support","Extended file versioning"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$Ultra (10TB)$q$, $q$$1,190 one-time lifetime$q$, $q$Lifetime$q$, NULL, $q$["10 TB storage","2 TB download link traffic","Highest storage tier available"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$pCloud is a cloud storage provider founded in 2013 and headquartered in Baar, Switzerland, best known for offering one-time lifetime payment plans as an alternative to recurring subscriptions used by most cloud storage competitors. Users pay once for a fixed amount of storage that remains active for as long as pCloud operates.$q$, $q$Beyond storage, pCloud provides cross-platform sync, a built-in media player for streaming stored video and audio, and optional client-side encryption for users who want an additional layer of privacy.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$pCloud syncs files across Windows, Mac, Linux, iOS, and Android, and lets users share files and folders through public links with optional passwords and expiration dates. Its built-in media player allows streaming video and audio directly from cloud storage without downloading files first.$q$, $q$For added privacy, pCloud Encryption (Crypto) is available as a paid add-on that encrypts a designated folder client-side so that not even pCloud can read its contents. Users can also choose whether their data is stored in EU or US data centers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0b7cc54-ec23-41b8-8746-9590d13dde47', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$pCloud offers a free tier with 10 GB of storage, monthly and annual subscription plans starting at $4.99 per month for 500 GB, and distinctive one-time lifetime plans starting at $199 for 500 GB, $399 for 2 TB, and $1,190 for 10 TB.$q$, $q$The lifetime plans require a larger upfront payment but eliminate recurring fees going forward, while subscriptions offer a lower-commitment way to access the same storage tiers. A Family plan lets up to five users share one storage pool.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$PDF annotation$q$, $q$Highlight, underline, add notes, and draw directly on PDF pages.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Text and image editing$q$, $q$Edit existing PDF text and images without needing the original source file.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Digital signatures$q$, $q$Add legally binding signatures and request signatures from others.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Form filling and creation$q$, $q$Fill out existing PDF forms or build new fillable forms.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$OCR$q$, $q$Recognize and extract text from scanned documents and images.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$PDF Copilot (AI assistant)$q$, $q$Summarize documents, ask questions, and get AI help directly within the app.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Merge, split, and organize pages$q$, $q$Combine multiple PDFs or rearrange and extract pages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Redaction$q$, $q$Permanently remove sensitive text or images from a document.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Native, well-designed apps for Mac, iPad, and iPhone$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$One-time Lifetime purchase option (Mac) as an alternative to subscription$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$AI-powered PDF Copilot assistant built in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Fast performance and Apple Pencil support on iPad$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Strong OCR and form-filling tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Lifetime license is limited to the Mac version only$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Weekly and annual subscription pricing can be costly compared to some competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$No native Windows or Android app, with a Mac/iOS/iPadOS focus$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Some advanced features are gated behind the Premium subscription$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Is PDF Expert free?$q$, $q$A free version is available with limited editing; full features require a Premium subscription or Lifetime license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Who makes PDF Expert?$q$, $q$PDF Expert is developed by Readdle, a software company founded in 2007 in Odesa, Ukraine.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Does PDF Expert work on Windows?$q$, $q$PDF Expert is primarily built for Mac, iPad, and iPhone; it does not have a native Windows app.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$What is PDF Copilot?$q$, $q$PDF Copilot is Readdle's AI assistant built into PDF Expert that can summarize and answer questions about document content.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Can I buy PDF Expert once instead of subscribing?$q$, $q$Yes, a one-time Lifetime license is available, but only for the Mac version.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Does PDF Expert support e-signatures?$q$, $q$Yes, users can add and request legally binding digital signatures.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Is there a student discount?$q$, $q$Yes, Readdle offers a discount on the annual plan for verified students and educators.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$What is the difference between PDF Expert and Adobe Acrobat?$q$, $q$PDF Expert is a lighter, more affordable, Apple-focused alternative, while Acrobat is a more feature-heavy, cross-platform, long-established industry standard.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Mac and iPad document editing for professionals$q$, $q$Professionals use PDF Expert to annotate, edit, and sign contracts and reports natively on Mac and iPad.$q$, $q$Business professionals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Student note-taking and study$q$, $q$Students annotate lecture slides and textbooks with Apple Pencil support on iPad.$q$, $q$Students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Digitizing and organizing scanned paperwork$q$, $q$Users scan paper documents, run OCR to make them searchable, and organize them into folders.$q$, $q$Small business owners and freelancers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["View PDFs","Basic annotation","Limited editing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Premium Weekly$q$, $q$EUR 5.99/week$q$, $q$Weekly$q$, NULL, $q$["Full editing and annotation","PDF Copilot AI assistant","OCR and form filling","Digital signatures"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Premium Yearly$q$, $q$EUR 84.99/year (about EUR 1.63/week)$q$, $q$Annual$q$, NULL, $q$["All Premium features","Priority support","Student discount available"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Lifetime (Mac only)$q$, $q$EUR 149.99 one-time$q$, $q$One-time$q$, NULL, $q$["All Premium features on Mac","No recurring payments","New feature releases may cost extra"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PDF Expert is a PDF editing and annotation app made by Readdle, a Ukrainian software company founded in 2007 in Odesa. The app is built primarily for Mac, iPad, and iPhone, offering a native Apple experience with support for Apple Pencil and touch-based editing.$q$, $q$PDF Expert combines core PDF tools such as annotation, editing, and form filling with newer AI-assisted features through PDF Copilot, positioning it as a faster and more affordable alternative to Adobe Acrobat for Apple-centric users.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users can annotate, edit text and images, merge and split files, fill and design forms, add digital signatures, redact sensitive content, and run OCR on scanned documents directly within PDF Expert.$q$, $q$PDF Copilot, Readdle's AI assistant built into the app, can summarize documents, answer questions about their content, and assist with translation and conversion to formats like Word, Excel, and PowerPoint.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PDF Expert can be downloaded for free with basic viewing and limited editing. Full functionality requires a Premium subscription priced at roughly EUR 5.99 per week or about EUR 84.99 per year, with a student discount available on the annual plan.$q$, $q$A one-time Lifetime license priced around EUR 149.99 is also available, though it is restricted to the Mac version only; new feature releases after purchase may cost extra.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Browser-based PDF viewer$q$, $q$Read PDFs directly in the browser with position memory across devices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Tagging, starring, and archiving$q$, $q$Multi-level organization tools to manage large PDF collections.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Lightweight editing$q$, $q$Add text, highlights, and drawings to PDF pages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Digital signatures$q$, $q$Sign PDFs and access signed documents from any device.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Sharing with access control$q$, $q$Share PDFs via links or QR codes, with optional passwords or expiration.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$SSO and 2FA$q$, $q$Supports OIDC single sign-on and two-factor authentication for secure deployments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Docker-based deployment$q$, $q$Set up quickly using Docker, Docker Compose, or Helm.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Dark mode and themes$q$, $q$Customizable interface appearance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Completely free and open source$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Full data ownership through self-hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Fast, minimal Docker-based setup$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Supports SSO/OIDC and two-factor authentication for security$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Actively maintained with growing community traction (1,700+ GitHub stars)$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Requires self-hosting knowledge and infrastructure with no managed cloud version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Smaller feature set than commercial PDF editors like Adobe Acrobat or PDF Expert$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$No official mobile app; relies on browser access$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Smaller community and support base than larger open-source document tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Is PdfDing free?$q$, $q$Yes, PdfDing is fully open source and free to self-host.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$How do I install PdfDing?$q$, $q$PdfDing is typically deployed using Docker, Docker Compose, or Helm for Kubernetes.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Does PdfDing have a hosted or cloud version?$q$, $q$No, PdfDing is designed to be self-hosted; there is no official managed cloud offering.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$What framework is PdfDing built on?$q$, $q$PdfDing is built using the Django web framework.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Can I edit PDFs in PdfDing?$q$, $q$Yes, it supports lightweight editing such as adding text, highlights, and drawings.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Does PdfDing support single sign-on?$q$, $q$Yes, it supports OIDC-based SSO and two-factor authentication.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Where is the PdfDing source code hosted?$q$, $q$On GitHub (mrmn2/PdfDing) and mirrored on Codeberg.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Who funds PdfDing's development?$q$, $q$The project has received funding through the NGI0 Commons Fund, backed by NLnet and the European Commission.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Self-hosted personal PDF library$q$, $q$Individuals who want to avoid cloud PDF services host PdfDing on a home server or NAS to manage their document collection privately.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Small team document sharing$q$, $q$Small teams self-host PdfDing to share and annotate PDFs internally with access-controlled links.$q$, $q$Small teams and developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Research and reading list management$q$, $q$Researchers and students use tagging and archiving to organize large collections of papers and reference PDFs.$q$, $q$Researchers and students$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","Docker, Docker Compose, and Helm deployment","All core features included","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PdfDing is an open-source, self-hosted PDF manager and viewer built with Django, designed to give users full ownership of their document storage. It is deployed with Docker and has gained notable traction in the self-hosting community, with over 1,700 stars on its GitHub repository.$q$, $q$The project received funding support from the NGI0 Commons Fund, backed by NLnet and the European Commission, reflecting its focus on privacy-respecting, open internet technology rather than a commercial product with a company behind it.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$PdfDing offers a browser-based PDF viewer that remembers reading position across devices, along with tagging, starring, and archiving tools for organizing large PDF collections. Lightweight editing lets users add text, highlights, and drawings, and digital signatures can be applied and accessed from any device.$q$, $q$Security-conscious deployments are supported through OIDC single sign-on and two-factor authentication, while sharing via links or QR codes with optional access control makes it easy to distribute documents to an external audience.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PdfDing is entirely free and open source, with no subscription tiers or paid version of the software itself. There is no official managed cloud offering.$q$, $q$The only cost users incur is their own hosting infrastructure, such as a VPS, home server, or NAS, which they choose and manage independently when self-hosting PdfDing via Docker, Docker Compose, or Helm.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7407b9cd-1500-4f27-a02b-adda67302c80', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Free online PDF editor$q$, $q$Edit text, images, and pages directly in the browser at no cost.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Form filling and creation$q$, $q$Fill existing PDF forms or design new fillable forms.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Annotation tools$q$, $q$Highlight, comment, and mark up PDF documents.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Desktop app (Premium/Ultimate)$q$, $q$Offline access with advanced editing tools.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$PDF creation from 300+ file types$q$, $q$Convert other file formats into PDF.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Merge and compress$q$, $q$Combine multiple PDFs or reduce file size.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Encryption and redaction$q$, $q$Password-protect files and permanently remove sensitive content.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$E-signatures$q$, $q$Add electronic signatures to documents.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Genuinely free online tier with real editing and form-filling capability$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$No installation required for the free browser-based editor$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Affordable Premium and Ultimate subscription pricing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Desktop app available for offline use on paid tiers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Backed by publicly traded Claranova, adding financial stability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Free tier limits file size to 10MB, 100 pages, and 10 stored files$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Free tier only retains file history for 7 days$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Interface feels dated compared to newer competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Advanced tools like redaction and encryption require a paid plan$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Is PDFescape really free?$q$, $q$Yes, the online editor has a genuinely free tier for basic editing and form filling, though with file size and storage limits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Who owns PDFescape?$q$, $q$PDFescape is owned by Avanquest, the software division of the publicly traded French group Claranova, which acquired it in March 2021.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$What is the difference between PDFescape Premium and Ultimate?$q$, $q$Premium removes ads and raises free-tier limits; Ultimate adds unlimited file history and a full desktop app with advanced tools.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Do I need to install PDFescape?$q$, $q$No, the free tier runs entirely in your web browser; a desktop app is available with Premium and Ultimate.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$What are PDFescape's free tier limits?$q$, $q$Files up to 10MB and 100 pages, a maximum of 10 stored files, and 7 days of file history.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Does PDFescape support e-signatures?$q$, $q$Yes, e-signature tools are available, primarily in the paid desktop app.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$How much does PDFescape Premium cost?$q$, $q$Premium starts at around $3 per month; Ultimate is around $6 per month.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Is PDFescape safe to use?$q$, $q$PDFescape has operated for many years and is now backed by the publicly traded Claranova group, though users should review its privacy policy before uploading sensitive documents.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Occasional online PDF editing$q$, $q$Users who need to make a quick edit or fill a form occasionally use the free browser-based editor without installing software.$q$, $q$General consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Small business form processing$q$, $q$Small businesses use Premium or Ultimate to fill, create, and manage larger volumes of PDF forms.$q$, $q$Small businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Offline PDF workflows$q$, $q$Professionals who need offline access use the Ultimate desktop app for merging, compressing, and redacting documents.$q$, $q$Professionals and administrative staff$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Online PDF editor","Form filling and creation","10MB/100-page file limit","10 stored files, 7-day history"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Premium$q$, $q$$3/month$q$, $q$Monthly$q$, NULL, $q$["Ad-free interface","40MB file limit, 100 stored files","30-day file history","7-day desktop app trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Ultimate$q$, $q$$6/month$q$, $q$Monthly$q$, NULL, $q$["All Premium features","Unlimited file history","Full desktop app access","Advanced tools: merge, compress, encrypt, redact, e-sign"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PDFescape is a browser-based PDF editor established in Montreal, Canada, by developers Roger Politis and Bruno Vanryb under the company CTdeveloping, LLC. It has offered a genuinely free online tier for basic editing and form filling since its early years, later being acquired in 2021 by Avanquest, the software division of the publicly traded French group Claranova.$q$, $q$Unlike many competitors that limit their free tier to a short trial, PDFescape's free online editor remains permanently free with usage limits, while Premium and Ultimate subscriptions unlock higher limits and a full desktop application.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The free online editor lets users edit PDF text and images, fill and design PDF forms, and annotate documents entirely within a web browser without installing any software.$q$, $q$The paid desktop app, available with Premium and Ultimate plans, adds advanced tools including PDF creation from over 300 file types, merging, compression, encryption, redaction, and e-signatures, along with unlimited file history on Ultimate.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PDFescape's free tier allows files up to 10 MB and 100 pages, stores up to 10 files, and retains 7 days of file history, with no watermark added to prints or downloads.$q$, $q$Premium is priced at around $3 per month and raises limits to 40 MB files, 100 stored files, and 30 days of history, while Ultimate at around $6 per month adds unlimited history and the full desktop application with advanced editing tools.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Client-side encryption$q$, $q$All files are encrypted on the user's device before ever reaching the server, using TweetNaCl in 5MiB chunks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Metadata protection$q$, $q$Filenames, file sizes, directory structure, and social graph are hidden from the server, not just file contents.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$IPFS-based storage$q$, $q$Uses the InterPlanetary File System for decentralized data storage, routing, and retrieval.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Secure messenger$q$, $q$Built-in encrypted messaging between Peergos users.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Encrypted email client and bridge$q$, $q$Send and receive encrypted email through Peergos.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Private social networking$q$, $q$Follow or friend other users without exposing the friendship graph publicly.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Fine-grained access control$q$, $q$Securely share specific files or folders with chosen contacts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Self-hosting support$q$, $q$Run your own Peergos server with local disk or S3-compatible storage.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Strong, audited (Cure53) end-to-end encryption of both data and metadata$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Fully open source under GPL/AGPL licenses$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Combines file storage, messaging, email, and social networking in one privacy-first platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Self-hosting option gives full control over infrastructure$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Free public beta available for users who do not want to self-host$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Smaller community and ecosystem compared to mainstream cloud storage providers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Self-hosting requires technical setup and ongoing maintenance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Feature set and polish are less mature than commercial alternatives like Dropbox or Tresorit$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Limited mobile app maturity compared to established competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Is Peergos free?$q$, $q$Yes, Peergos is free and open source; the public beta is free to use, and self-hosting only costs your own infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$What encryption does Peergos use?$q$, $q$Peergos encrypts data client-side with TweetNaCl before upload, and also protects metadata like filenames and directory structure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$What is Peergos built on?$q$, $q$Peergos uses IPFS for decentralized storage, routing, and retrieval of encrypted data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Can I self-host Peergos?$q$, $q$Yes, Peergos can be self-hosted using local disk storage or S3-compatible object storage.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Does Peergos have social networking features?$q$, $q$Yes, it includes a private social layer for following or friending other users without exposing the friend graph.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Has Peergos been security audited?$q$, $q$Yes, the project has been audited by the security firm Cure53.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$When did Peergos start?$q$, $q$Peergos began as a side project in 2013.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$What license does Peergos use?$q$, $q$Peergos clients are licensed under GPL and the server under AGPL.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Private encrypted file storage$q$, $q$Privacy-conscious users store personal files with client-side encryption that even the server operator cannot read.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Self-hosted alternative to commercial cloud storage$q$, $q$Organizations and activists self-host Peergos to avoid dependence on centralized cloud storage providers.$q$, $q$Organizations and activists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Private social networking and messaging$q$, $q$Users who want to communicate and share updates without exposing their social graph use Peergos's messenger and social layer.$q$, $q$Privacy-focused communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$Public Beta / Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Free public beta account at peergos.net","Full self-hosting option","Client-side encrypted storage","Messenger, email, and social features included"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Peergos began in 2013 as a side project among a group of friends, including co-founder Ian Preston, and has grown into an open-source, peer-to-peer encrypted global filesystem and application protocol. It is fully free and open source, with clients licensed under GPL and the server under AGPL.$q$, $q$Built on top of IPFS for decentralized data storage and routing, Peergos encrypts all data client-side before it ever leaves a user's device, and has been security audited by Cure53, positioning it as a privacy-first alternative to mainstream cloud storage and social platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Peergos encrypts files client-side in independently encrypted 5MiB chunks using TweetNaCl, and goes further than typical encrypted storage tools by hiding metadata such as filenames, file sizes, directory structure, and social-graph information from the server.$q$, $q$Beyond file storage, Peergos includes a secure messenger, an encrypted email client and bridge, and a private social networking layer that lets users follow or friend each other without exposing their friendship graph.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Peergos has no subscription pricing since it is a volunteer-driven open-source project rather than a commercial company. Users can try it through a free public beta hosted at peergos.net.$q$, $q$Alternatively, users and organizations can self-host their own Peergos instance using local disk storage or S3-compatible object storage, in which case the only cost is their own infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6081e57b-98a6-4413-b8d5-be18ac3034df', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Federated instances (ActivityPub)$q$, $q$Independent PeerTube servers can interconnect, letting users discover and interact with videos across the Fediverse.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Peer-to-peer streaming$q$, $q$WebRTC and HLS-based P2P playback reduces bandwidth costs for instance operators.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Self-hosting$q$, $q$Anyone can run their own PeerTube instance and set their own moderation and content rules.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Live streaming$q$, $q$Supports live video broadcasting in addition to uploaded video-on-demand content.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Playlists and channels$q$, $q$Organize videos into channels and playlists similar to mainstream video platforms.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Content moderation tools$q$, $q$Instance admins control federation, comments, and content policies for their server.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$No centralized advertising or recommendation algorithm$q$, $q$Avoids the ad-driven recommendation model used by mainstream video platforms.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Multi-language interface$q$, $q$Available in roughly 28 languages through community translations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Fully free and open source with no centralized company controlling the network$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Decentralized and federated design avoids single points of control or failure$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Peer-to-peer streaming reduces hosting bandwidth costs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Instance operators set their own moderation and community rules$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Backed by Framasoft, an established non-profit with a multi-year development track record$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Requires self-hosting or finding a third-party instance, unlike a single unified platform$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Smaller audience reach than YouTube, which can limit content discovery$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Setup and server maintenance require technical knowledge$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Feature parity with YouTube on recommendation and monetization tools is limited$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Is PeerTube free?$q$, $q$Yes, the software is free and open source; costs only arise if you choose to pay for storage or hosting on someone else's instance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Who created PeerTube?$q$, $q$A developer known as Chocobozzz started PeerTube in 2017, with development later supported by the French non-profit Framasoft.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$How is PeerTube different from YouTube?$q$, $q$PeerTube is decentralized: instead of one company hosting all videos, independent instances federate together using ActivityPub, with no central ads or recommendation algorithm.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Can I run my own PeerTube server?$q$, $q$Yes, PeerTube is designed to be self-hosted by anyone with server infrastructure.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Does PeerTube support live streaming?$q$, $q$Yes, PeerTube supports live video broadcasts in addition to on-demand uploads.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$What license does PeerTube use?$q$, $q$PeerTube is licensed under the AGPLv3+.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$What is Framasoft's role in PeerTube?$q$, $q$Framasoft, a Lyon-based French non-profit, hired PeerTube's original developer and funds ongoing development through crowdfunding and grants.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Does PeerTube use peer-to-peer technology?$q$, $q$Yes, it uses WebRTC and HLS-based peer-to-peer streaming to reduce bandwidth load on instance servers.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Independent content creator hosting$q$, $q$Creators who want to avoid platform demonetization or algorithmic suppression host their own PeerTube channel or join a community instance.$q$, $q$Independent content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Institutional and educational video hosting$q$, $q$Universities and organizations run their own PeerTube instance to host lecture and training videos under their own control.$q$, $q$Universities and institutions$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Community and activist media platforms$q$, $q$Community groups and activist organizations use PeerTube instances to publish video content outside of corporate platform moderation.$q$, $q$Community and activist groups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Self-Hosted Instance (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","Unlimited videos, limited only by your own server storage","Full moderation and federation control","AGPLv3+ licensed"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$Third-Party Hosted Instance$q$, $q$Custom (varies by instance/provider)$q$, $q$Custom$q$, NULL, $q$["No server maintenance required","Storage and bandwidth limits vary by provider","Some instances offer paid storage tiers"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PeerTube is a free and open-source video hosting platform started in 2017 by developer Chocobozzz and supported since by Framasoft, a French non-profit association headquartered in Lyon that promotes free software and digital commons education. The first stable 1.0 release arrived in October 2018.$q$, $q$Rather than one company running centralized infrastructure, PeerTube lets anyone host their own instance, with independent instances federating together through the ActivityPub protocol as part of the wider Fediverse alongside platforms like Mastodon.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$PeerTube supports both uploaded video-on-demand content and live streaming, organized into channels and playlists similar to mainstream video platforms. Instance administrators control their own moderation policies, federation choices, and comment settings.$q$, $q$To reduce hosting costs, PeerTube uses peer-to-peer streaming via WebRTC and HLS, letting viewers share video data with one another while watching, easing the bandwidth burden on any single server.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PeerTube itself is free, open-source software licensed under AGPLv3+, with no central company charging a subscription for the platform. Anyone can download and self-host it at no software cost.$q$, $q$Costs only arise from the infrastructure needed to run an instance, or from choosing to use a third-party PeerTube instance that charges for storage, bandwidth, or hosting rather than running your own server.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('43fecc1e-117b-4ec8-ae44-12dc137692b9', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
